import json
from datetime import datetime
from flask import Flask, request, make_response

app = Flask(__name__)
cache = {}

def get_cache(key):
    if key not in cache:
        return None
    else:
        return cache[key]

def set_cache(key, value):
    cache[key] = value

@app.route('/', methods=['GET'])
def index():
    key = request.args.get('key')
    if not key:
        return 'No key provided', 400
    
    cached_response = get_cache(key)
    if cached_response is None:
        # API call to fetch data goes here
        response = make_response(json.dumps({'data': {'foo': 'bar'}}))
        set_cache(key, response)
        return response
    
    else:
        expiration = datetime.strptime(cached_response['expiration'], '%Y-%m-%dT%H:%M:%S')
        if datetime.now() > expiration:
            # API call to fetch data goes here
            response = make_response(json.dumps({'data': {'foo': 'bar'}}))
            set_cache(key, response)
            return response
        
        else:
            return cached_response['data']

if __name__ == '__main__':
    app.run()